 * CORS headers to allow JavaScript access to loaded resources.
 * This is necessary for features like accessing contentDocument of SVG files
 * loaded via <object> tags, which would otherwise be blocked by same-origin policy.
 */
private val CORS_HEADERS = mapOf("Access-Control-Allow-Origin" to "*")

fun Context.getViewerAssetLoader(domain: String): WebViewAssetLoader {
    val mediaDir = CollectionHelper.getMediaDirectory(this)
    return WebViewAssetLoader.Builder()
        .setHttpAllowed(true)
        .setDomain(domain)
        .addPathHandler("/") { path: String ->
            if (path == "favicon.ico") {
                return@addPathHandler WebResourceResponse(
                    "image/x-icon",
                    null,
                    200,
                    "OK",
                    CORS_HEADERS,
                    ByteArrayInputStream(ByteArray(0))
                )
            }
            try {
                val file = File(mediaDir, path)
                val inputStream = FileInputStream(file)
                WebResourceResponse(
                    guessMimeType(path),
                    null,
                    200,
                    "OK",
                    CORS_HEADERS,
                    inputStream
                )
            } catch (e: Exception) {
                Timber.d("File not found: %s", path)
                null
            }
        }
        .build()
}"}

