     * Remove binding from all control preferences.
     * Searches through the entire preference screen (parent of parent) since
     * control preferences are organized in multiple category groups.
     */
    private fun clearBinding(binding: MappableBinding) {
        // Parent is the PreferenceCategory, and its parent is the PreferenceScreen
        val preferenceScreen = parent?.parent
            ?: return

        for (command in ViewerCommand.entries) {
            val commandPreference = preferenceScreen.findPreference<ControlPreference>(command.preferenceKey)
                ?: continue
            val bindings = MappableBinding.fromPreferenceString(commandPreference.value)
            if (binding in bindings) {
                bindings.remove(binding)
                commandPreference.value = bindings.toPreferenceString()
            }
        }
    }"}

