package com.ichi2.anki.cardviewer

import com.google.common.base.Joiner
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Test

class ViewerCommandTest {

    @Test
    fun preference_keys_are_not_changed() {
        val names = Joiner.on(", ").join(ViewerCommand.entries.map { x -> x.preferenceKey })

        // NONE OF THESE SHOULD BE CHANGED OR A USER WILL LOSE THE ASSOCIATED PREFERENCES
        // Adds are acceptable
        // Deletes are acceptable if the binding should no longer exist
        assertEquals(
            "binding_SHOW_ANSWER, binding_FLIP_OR_ANSWER_EASE1, " +
                "binding_FLIP_OR_ANSWER_EASE2, binding_FLIP_OR_ANSWER_EASE3, binding_FLIP_OR_ANSWER_EASE4, " +
                "binding_UNDO, binding_EDIT, binding_MARK, binding_BURY_CARD, " +
                "binding_SUSPEND_CARD, binding_DELETE, binding_PLAY_MEDIA, " +
                "binding_EXIT, binding_BURY_NOTE, binding_SUSPEND_NOTE, binding_TOGGLE_FLAG_RED, " +
                "binding_TOGGLE_FLAG_ORANGE, binding_TOGGLE_FLAG_GREEN, binding_TOGGLE_FLAG_BLUE, " +
                "binding_TOGGLE_FLAG_PINK, binding_TOGGLE_FLAG_TURQUOISE, binding_TOGGLE_FLAG_PURPLE, " +
                "binding_UNSET_FLAG, binding_PAGE_UP, binding_PAGE_DOWN, binding_TAG, binding_CARD_INFO, binding_ABORT_AND_SYNC, " +
                "binding_RECORD_VOICE, binding_REPLAY_VOICE, binding_TOGGLE_WHITEBOARD, binding_CLEAR_WHITEBOARD, " +
                "binding_CHANGE_WHITEBOARD_PEN_COLOR, binding_SHOW_HINT, binding_SHOW_ALL_HINTS, binding_ADD_NOTE, " +
                "binding_RESCHEDULE_NOTE",
            names
        )
    }

    /**
     * Verifies that all ViewerCommand entries have a valid CommandGroup assigned.
     * This test ensures that when new commands are added, they are properly categorized
     * for display in the Controls preferences screen.
     */
    @Test
    fun all_commands_have_a_valid_group() {
        val commandsByGroup = ViewerCommand.entries.groupBy { it.group }

        // Verify all CommandGroup values are used
        for (group in CommandGroup.entries) {
            val commands = commandsByGroup[group]
            assertTrue(
                "CommandGroup.$group should have at least one command assigned",
                !commands.isNullOrEmpty()
            )
        }

        // Verify all commands have a group (implicitly guaranteed by enum design, but good to document)
        for (command in ViewerCommand.entries) {
            assertTrue(
                "ViewerCommand.${command.name} should have a non-null group",
                CommandGroup.entries.contains(command.group)
            )
        }
    }

    /**
     * Documents the expected grouping of commands.
     * If this test fails after adding a new command, update the expected counts accordingly.
     */
    @Test
    fun command_groups_have_expected_counts() {
        val commandsByGroup = ViewerCommand.entries.groupBy { it.group }

        // These counts should be updated when commands are added/removed/moved between groups
        assertEquals("ANSWER group", 5, commandsByGroup[CommandGroup.ANSWER]?.size)
        assertEquals("FLAGS group", 8, commandsByGroup[CommandGroup.FLAGS]?.size)
        assertEquals("CARD_OR_NOTE group", 11, commandsByGroup[CommandGroup.CARD_OR_NOTE]?.size)
        assertEquals("WHITEBOARD group", 3, commandsByGroup[CommandGroup.WHITEBOARD]?.size)
        assertEquals("AUDIO group", 3, commandsByGroup[CommandGroup.AUDIO]?.size)
        assertEquals("NAVIGATION group", 3, commandsByGroup[CommandGroup.NAVIGATION]?.size)
        assertEquals("OTHER group", 2, commandsByGroup[CommandGroup.OTHER]?.size)

        // Total should match all commands
        val totalInGroups = commandsByGroup.values.sumOf { it.size }
        assertEquals("Total commands in groups should match ViewerCommand.entries count", ViewerCommand.entries.size, totalInGroups)
    }
}"}

