}", "new_string": "/**
 * Parses the sources of the `<img>`, `<video>`, `<audio>`, `<object>` and `<source>` tags
 * to use the `file:///` scheme, which allows seeking audio and videos,
 * and loads faster than using HTTP.
 *
 * Only attribute values that don't have a Uri scheme (http, file, etc) are parsed.
 */
@NotInLibAnki
@VisibleForTesting
fun parseSourcesToFileScheme(content: String, mediaDir: String): String {
    val doc = Jsoup.parse(content)
    doc.outputSettings(OutputSettings().prettyPrint(false))

    // Collect replacements to apply to the original content string.
    // This preserves the original HTML structure (including <script> tags)
    // that would be lost if we used Jsoup's html() output.
    val replacements = mutableListOf<Pair<String, String>>()

    fun collectReplacementsWithFileScheme(tag: String, attr: String) {
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue

            val attrUri = try {
                URI(attrValue)
            } catch (_: URISyntaxException) {
                continue
            }
            if (attrUri.scheme != null) continue

            val path = Paths.get(mediaDir, attrUri.path).toString()
            val newUri = getFileUri(path)

            replacements.add(attrValue to newUri.toString())
        }
    }

    collectReplacementsWithFileScheme("img", "src")
    collectReplacementsWithFileScheme("video", "src")
    collectReplacementsWithFileScheme("audio", "src")
    collectReplacementsWithFileScheme("source", "src")
    collectReplacementsWithFileScheme("object", "data")

    if (replacements.isEmpty()) {
        return content
    }

    var result = content
    for ((oldValue, newValue) in replacements) {
        result = result.replace(oldValue, newValue)
    }
    return result
}"}

