/**
 * How to sort the rows in the [CardBrowser]
 *
 * This is an adapter from our [SharedPreferences] based handling of sorting
 * to Anki's [Config]
 *
 * We can likely remove the SharedPreferences and rely entirely on Anki
 *
 * @param ankiSortType The value to be passed into Anki's "sortType" config
 * @param cardBrowserLabelIndex The index into [R.array.card_browser_order_labels]
 */
@Suppress("unused") // 'unused' entries are iterated over by .entries
enum class SortType(val ankiSortType: String?, val cardBrowserLabelIndex: Int) {
    NO_SORTING(null, 0),
    SORT_FIELD("noteFld", 1),
    CREATED_TIME("noteCrt", 2),
    NOTE_MODIFICATION_TIME("noteMod", 3),
    CARD_MODIFICATION_TIME("cardMod", 4),
    DUE_TIME("cardDue", 5),
    INTERVAL("cardIvl", 6),
    EASE("cardEase", 7),
    REVIEWS("cardReps", 8),
    LAPSES("cardLapses", 9);

    fun save(config: Config, preferences: SharedPreferences, cardsOrNotes: CardsOrNotes) {
        // in the case of 'no sorting', we still need a sort type.
        // The inverse is handled in `fromCol`
        val sortTypeKey = getSortTypeConfigKey(cardsOrNotes)
        val noSortingPrefKey = getNoSortingPrefKey(cardsOrNotes)
        config.set(sortTypeKey, this.ankiSortType ?: SORT_FIELD.ankiSortType)
        preferences.edit {
            putBoolean(noSortingPrefKey, this@SortType == NO_SORTING)
        }
    }

    /** Converts the [SortType] to a [SortOrder] */
    fun toSortOrder(): SortOrder =
        if (this == NO_SORTING) SortOrder.NoOrdering() else SortOrder.UseCollectionOrdering()

    companion object {
        /** Config key for sort type in cards mode */
        const val SORT_TYPE_CARDS_CONFIG_KEY = "sortType"
        /** Config key for sort type in notes mode */
        const val SORT_TYPE_NOTES_CONFIG_KEY = "noteSortType"
        /** Config key for sort order (ascending/descending) in cards mode */
        const val SORT_BACKWARDS_CARDS_CONFIG_KEY = "sortBackwards"
        /** Config key for sort order (ascending/descending) in notes mode */
        const val SORT_BACKWARDS_NOTES_CONFIG_KEY = "browserNoteSortBackwards"
        /** Preference key for "no sorting" option in cards mode */
        private const val NO_SORTING_CARDS_PREF_KEY = "cardBrowserNoSorting"
        /** Preference key for "no sorting" option in notes mode */
        private const val NO_SORTING_NOTES_PREF_KEY = "cardBrowserNoSortingNotes"

        fun getSortTypeConfigKey(cardsOrNotes: CardsOrNotes): String =
            when (cardsOrNotes) {
                CardsOrNotes.CARDS -> SORT_TYPE_CARDS_CONFIG_KEY
                CardsOrNotes.NOTES -> SORT_TYPE_NOTES_CONFIG_KEY
            }

        fun getSortBackwardsConfigKey(cardsOrNotes: CardsOrNotes): String =
            when (cardsOrNotes) {
                CardsOrNotes.CARDS -> SORT_BACKWARDS_CARDS_CONFIG_KEY
                CardsOrNotes.NOTES -> SORT_BACKWARDS_NOTES_CONFIG_KEY
            }

        private fun getNoSortingPrefKey(cardsOrNotes: CardsOrNotes): String =
            when (cardsOrNotes) {
                CardsOrNotes.CARDS -> NO_SORTING_CARDS_PREF_KEY
                CardsOrNotes.NOTES -> NO_SORTING_NOTES_PREF_KEY
            }

        fun fromCol(config: Config, preferences: SharedPreferences, cardsOrNotes: CardsOrNotes): SortType {
            val sortTypeKey = getSortTypeConfigKey(cardsOrNotes)
            val noSortingPrefKey = getNoSortingPrefKey(cardsOrNotes)
            val colOrder = config.get<String>(sortTypeKey)
