413→        // This function shouldn't exist and CardBrowser should be modified to use Notes,
414→        // so not much effort was expended here
415→
416→        val noteIds = findNotes(query, order)
417→        if (noteIds.isEmpty()) return emptyList()
418→        // select the card with the lowest `ord` to show
419→        val noteIdToCardId = mutableMapOf<NoteId, CardId>()
420→        db.query(
421→            """
422→SELECT c.id, c.nid
423→FROM (
424→  SELECT nid, MIN(ord) AS ord
425→  FROM cards
426→  WHERE nid IN ${Utils.ids2str(noteIds)} 
427→  GROUP BY nid
428→) AS card_with_min_ord
429→JOIN cards AS c ON card_with_min_ord.nid = c.nid AND card_with_min_ord.ord = c.ord;
430→            """.trimMargin()
431→        ).use { cursor ->
432→            while (cursor.moveToNext()) {
433→                val cardId = cursor.getLong(0)
434→                val noteId = cursor.getLong(1)
435→                noteIdToCardId[noteId] = cardId
436→            }
437→        }
438→        // Return card IDs in the same order as note IDs
439→        return noteIds.mapNotNull { noteIdToCardId[it] }

