        var madeChanges = false
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue

            // Skip if the attribute value already has a URI scheme.
            // We avoid parsing the raw filename as a URI because special characters like '#'
            // would be incorrectly interpreted (e.g., 'image#1.png' would have '#1.png' as fragment).
            // Instead, we check for common schemes directly:
            // - "://" handles http://, https://, file://, etc.
            // - "data:" handles data URIs (data:image/png;base64,...)
            if (attrValue.contains("://") || attrValue.startsWith("data:", ignoreCase = true)) continue

            val path = Paths.get(mediaDir, attrValue).toString()
            val newUri = getFileUri(path)

            elem.attr(attr, newUri.toString())
            madeChanges = true
        }
        return madeChanges
    }"}

