 * Given a card index, returns the 'ord' of the card
 */
private fun Note.cardIndexToOrd(index: Int): Int {
    // We can't use note.numberOfCards() as this uses the database value
    return when {
        this.notetype.isCloze -> col.clozeNumbersInNote(this)[index] - 1
        else -> index
    }
}

/**
 * Converts a card ordinal to a card index for the previewer.
 * For non-cloze note types, the ordinal equals the index.
 * For cloze note types, the ordinal is the cloze number minus 1, so we need to find
 * the position in the list of actual cloze numbers present in the note.
 *
 * @param col The collection
 * @param ordinal The card's 'ord' value (cloze number - 1 for cloze types)
 * @param notetype The note type
 * @param fieldValues The field values (needed to compute cloze numbers)
 * @return The card index to use in the previewer
 */
private fun ordinalToIndex(col: Collection, ordinal: Int, notetype: NotetypeJson?, fieldValues: List<String>): Int {
    if (notetype == null || !notetype.isCloze) {
        return ordinal
    }
    // For cloze, we need to find which card index corresponds to this ordinal
    val note = col.newNote(notetype)
    // Set field values so we can compute cloze numbers
    for (i in fieldValues.indices) {
        if (i < note.fields.size) {
            note.setField(i, fieldValues[i])
        }
    }
    val clozeNumbers = col.clozeNumbersInNote(note)
    // ordinal for cloze is clozeNumber - 1, so we search for ordinal + 1
    val index = clozeNumbers.indexOf(ordinal + 1)
    return if (index >= 0) index else 0
}"}

