        /**
         * Migrates `FLIP_OR_ANSWER_RECOMMENDED` bindings to `FLIP_OR_ANSWER_EASE3`
         * and `FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED` bindings to `FLIP_OR_ANSWER_EASE4`
         *
         * These commands were functionally identical, so this migration preserves user bindings.
         */
        internal class UpgradeRecommendedBindingsToEaseBindings : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE3
                )
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE4
                )
            }

            private fun migrateBindings(
                preferences: SharedPreferences,
                oldKey: String,
                newCommand: ViewerCommand
            ) {
                val oldBindings = preferences.getString(oldKey, null) ?: return
                if (oldBindings.isBlank()) {
                    preferences.edit { remove(oldKey) }
                    return
                }

                val bindings = MappableBinding.fromPreference(preferences, newCommand)
                val oldBindingsList = MappableBinding.fromPreferenceString(oldKey)

                for (binding in oldBindingsList) {
                    if (!bindings.contains(binding)) {
                        bindings.add(binding)
                    }
                }

                preferences.edit {
                    putString(newCommand.preferenceKey, bindings.toPreferenceString())
                    remove(oldKey)
                }
            }
        }
    }
}"}

